// Java 25 exam prep - Localization
// Learn: format currency and percentages for a Locale.
// Locale selects language and regional formatting rules.
Locale locale = Locale.forLanguageTag("sv-SE");
NumberFormat currency = NumberFormat.getCurrencyInstance(locale);
NumberFormat percent = NumberFormat.getPercentInstance(locale);
System.out.println(currency.format(1299.5));
System.out.println(percent.format(0.075));
